package com.mengwei.localgrowth.execution;
import com.fasterxml.jackson.databind.ObjectMapper;import com.mengwei.localgrowth.identity.AuthService.Identity;import com.mengwei.localgrowth.model.*;import com.mengwei.localgrowth.shared.ApiExceptionHandler.ApiException;import java.time.OffsetDateTime;import java.util.*;import org.springframework.http.HttpStatus;import org.springframework.jdbc.core.JdbcTemplate;import org.springframework.stereotype.Service;
@Service public class RealContentService{
 private final JdbcTemplate jdbc;private final OpenAiCompatibleProvider provider;private final ObjectMapper mapper=new ObjectMapper();private static final Set<String> CHANNELS=Set.of("WEBSITE","XIAOHONGSHU","DIANPING","DOUYIN","WECHAT","ZHIHU");
 public RealContentService(JdbcTemplate j,OpenAiCompatibleProvider p){jdbc=j;provider=p;}public Map<String,Object> status(){return Map.of("provider",provider.name(),"configured",provider.configured());}
 public Map<String,Object> testConnection(){var a=provider.invoke("仅返回连接测试成功的JSON：{\"ok\":true}","","","中国");return Map.of("provider",provider.name(),"model",a.model(),"success",true,"durationMs",a.durationMs(),"httpStatus",a.httpStatus(),"tokenUsage",Objects.requireNonNullElse(a.tokenUsage(),0L));}
 public Map<String,Object> generate(Identity i,UUID id,String channel){if(!CHANNELS.contains(channel))throw bad("CHANNEL_INVALID","不支持的内容平台");var t=one("select t.*,m.id merchant_id,m.name merchant_name,m.city,m.district from optimization_tasks t join merchants m on m.id=t.merchant_id where t.id=? and t.tenant_id=?",id,i.tenantId());var f=one("select name,aliases,website,services,claims from brands where merchant_id=? and tenant_id=? and deleted=false order by created_at limit 1",t.get("merchant_id"),i.tenantId());List<String> miss=new ArrayList<>();for(String k:new String[]{"name","services","claims"})if(blank(f.get(k)))miss.add(k);String facts="品牌名称："+safe(f.get("name"))+"；别名："+safe(f.get("aliases"))+"；城市："+safe(t.get("city"))+"；区域："+safe(t.get("district"))+"；服务："+safe(f.get("services"))+"；已验证主张/价格/案例："+safe(f.get("claims"))+"；官网："+safe(f.get("website"));String fj=json(Map.of("verifiedFacts",facts));UUID rid=UUID.randomUUID();String pv="real-content-v0.4.1";if(!miss.isEmpty()){save(i,rid,t,null,fj,json(miss),"[]",0L,"BLOCKED","缺少已验证资料："+String.join(",",miss),pv,null);return Map.of("generationBlocked",true,"missingFacts",miss,"reason","资料不足，未调用模型","provider",provider.name(),"promptVersion",pv);}try{var a=provider.invoke("你是本地商家内容编辑。必须只返回JSON，字段包括title、content、usedFacts、missingFacts、riskFlags、suggestedImages、callToAction、generationNotes。内容身份必须写明‘商家官方内容，不得冒充消费者UGC’。只能使用已验证事实，禁止编造价格、地址、营业时间、功效、医疗结论、案例、资质、销量、获奖或联系方式。\n已验证事实："+facts+"\n当前Gap："+t.get("description")+"\n目标问题："+t.get("target_question_ids")+"\n平台："+channel+"\n任务类型："+t.get("task_type"),String.valueOf(f.get("name")),String.valueOf(f.get("services")),String.valueOf(t.get("city")));Map<String,Object> p=parse(a.text());String content=String.valueOf(p.getOrDefault("content",""));if(content.isBlank()||!p.containsKey("title")){save(i,rid,t,null,fj,"[]","[]",a.tokenUsage(),"FAILED","模型结构化响应缺少title或content",pv,a);throw bad("MODEL_RESPONSE_INVALID","模型未返回完整结构化内容，未保存草稿");}List<String> risks=risks(content),used=strings(p.get("usedFacts"));for(String x:used)if(!facts.contains(x))risks.add("FACT_NOT_VERIFIED");risks.addAll(strings(p.get("riskFlags")));UUID asset=asset(i,t,channel,content,fj,risks,pv);save(i,rid,t,asset,fj,json(strings(p.get("missingFacts"))),json(risks),a.tokenUsage(),"SUCCEEDED",null,pv,a);Map<String,Object> out=new LinkedHashMap<>();out.put("generationBlocked",false);out.put("provider",provider.name());out.put("model",a.model());out.put("promptVersion",pv);out.put("generatedContent",content);out.put("title",p.get("title"));out.put("usedFacts",used);out.put("missingFacts",strings(p.get("missingFacts")));out.put("riskFlags",risks);out.put("suggestedImages",strings(p.get("suggestedImages")));out.put("callToAction",String.valueOf(p.getOrDefault("callToAction","")));out.put("generationNotes",String.valueOf(p.getOrDefault("generationNotes","")));out.put("aiGenerationId",rid);out.put("contentAssetId",asset);return out;}catch(Exception e){if(e instanceof ApiException ae&&!("MODEL_RESPONSE_INVALID".equals(ae.code())))save(i,rid,t,null,fj,"[]","[]",0L,"FAILED",ae.getMessage(),pv,null);else if(!(e instanceof ApiException))save(i,rid,t,null,fj,"[]","[]",0L,"FAILED",e.getMessage(),pv,null);if(e instanceof ApiException ae)throw ae;throw new ApiException(HttpStatus.BAD_GATEWAY,"MODEL_CALL_FAILED","真实模型调用失败，调用记录已保存");}}
 private UUID asset(Identity i,Map<String,Object> t,String c,String text,String facts,List<String> r,String p){UUID id=UUID.randomUUID();OffsetDateTime n=OffsetDateTime.now();jdbc.update("insert into content_assets (id,tenant_id,merchant_id,source_task_id,channel,title,content,fact_snapshot,prompt_version,generation_version,human_edited_content,risk_flags,review_status,created_at,updated_at,created_by,updated_by,version) values (?,?,?,?,?,?,?,?::jsonb,?,?,?,?::jsonb,?,?,?,?,?,?)",id,i.tenantId(),t.get("merchant_id"),t.get("id"),c,"真实模型草稿｜"+t.get("title"),text,facts,p,"real-model-v1",null,json(r),"DRAFT",n,n,i.userId(),i.userId(),0L);return id;}
 private void save(Identity i,UUID id,Map<String,Object> t,UUID a,String f,String m,String r,Long tok,String st,String err,String p,ModelProviderPort.ModelAnswer x){String generated=a==null?"":jdbc.queryForObject("select content from content_assets where id=?",String.class,a);jdbc.update("insert into ai_generation_records (id,tenant_id,merchant_id,source_task_id,content_asset_id,provider,model,prompt_version,input_facts,generated_content,missing_facts,risk_flags,token_usage,created_at,created_by,execution_status,error_message,request_started_at,response_duration_ms,http_status,raw_response_summary,structured_output) values (?,?,?,?,?,?,?,?,?::jsonb,?,?::jsonb,?::jsonb,?,?,?,?,?,?,?,?,?,?::jsonb)",id,i.tenantId(),t.get("merchant_id"),t.get("id"),a,provider.name(),provider.configuredModel(),p,f,generated,m,r,tok,OffsetDateTime.now(),i.userId(),st,err,null,x==null?null:x.durationMs(),x==null?null:x.httpStatus(),x==null?null:x.rawResponse(),null);}
 private List<String> risks(String s){List<String>r=new ArrayList<>();if(s.matches("(?s).*(治疗|治愈|疗效|根治|医学证明).*"))r.add("MEDICAL_PROMISE");if(s.matches("(?s).*(最好|第一|百分之百|保证|全网).*"))r.add("ABSOLUTE_CLAIM");if(s.matches("(?s).*(客户说|顾客表示|亲身体验|案例显示).*"))r.add("UNVERIFIED_CASE");if(s.matches("(?s).*(五星好评|刷好评|虚假评价|带节奏).*"))r.add("FAKE_REVIEW");return r;}
 @SuppressWarnings("unchecked")private Map<String,Object> parse(String raw){String s=raw==null?"":raw.trim();if(s.startsWith("```"))s=s.replaceFirst("^```(?:json)?\\s*","").replaceFirst("\\s*```$","").trim();try{return mapper.readValue(s,Map.class);}catch(Exception e){throw bad("MODEL_RESPONSE_INVALID","模型返回不是合法JSON，未保存草稿");}}
 private List<String> strings(Object v){if(!(v instanceof Collection<?> c))return List.of();return c.stream().map(String::valueOf).toList();}private String json(Object o){try{return mapper.writeValueAsString(o);}catch(Exception e){throw new IllegalStateException(e);}}private Map<String,Object> one(String q,Object...a){var r=jdbc.queryForList(q,a);if(r.isEmpty())throw bad("NOT_FOUND","任务或商家资料不存在");return r.getFirst();}private ApiException bad(String c,String m){return new ApiException(HttpStatus.BAD_REQUEST,c,m);}private boolean blank(Object x){return x==null||String.valueOf(x).isBlank()||"无".equals(String.valueOf(x));}private String safe(Object x){return x==null?"未填写":String.valueOf(x);}
}
